mapper.select:
SELECT 'ROOM' AS type , R.RM_RSVT_NO AS resId , M.RM_NM AS title , R.RM_RSVT_EXPLN AS expln , TO_CHAR(R.RM_RSVT_BGNG_DT, 'YYYY-MM-DD HH24:MI') AS bgngDt , TO_CHAR(R.RM_RSVT_END_DT, 'YYYY-MM-DD HH24:MI') AS endDt , CASE WHEN R.APRV_STTS = 'REJECTED' THEN '반려됨' WHEN R.APRV_STTS = 'CONFIRMED' THEN '예약 확정' WHEN R.RM_RSVT_APRV_DT IS NOT NULL THEN '예약 확정' ELSE '승인 대기' END AS stts , TO_CHAR(R.RM_RSVT_APRV_DT, 'YYYY-MM-DD HH24:MI') AS aprvDt , NULL AS fixtCat FROM ROOM_RESERVATION R JOIN MEETING_ROOM M ON R.RM_NO = M.RM_NO WHERE R.EMP_ID = #{empId}
UNION ALL
SELECT 'FIXTURE' AS type , FR.FIXT_RSVT_NO AS resId , F.FIXT_NM AS title , FR.FIXT_RSVT_EXPLN AS expln , TO_CHAR(FR.FIXT_RSVT_BGNG_DT, 'YYYY-MM-DD HH24:MI') AS bgngDt , TO_CHAR(FR.FIXT_RSVT_END_DT, 'YYYY-MM-DD HH24:MI') AS endDt , CASE WHEN FR.APRV_STTS = 'REJECTED' THEN '반려됨' WHEN FR.APRV_STTS = 'CONFIRMED' THEN '예약 확정' WHEN FR.FIXT_RSVT_APRV_DT IS NOT NULL THEN '예약 확정' ELSE '승인 대기' END AS stts , TO_CHAR(FR.FIXT_RSVT_APRV_DT,'YYYY-MM-DD HH24:MI') AS aprvDt , F.FIXT_CAT AS fixtCat FROM FIXTURE_RESERVATION FR JOIN FIXTURE F ON FR.FIXT_NO = F.FIXT_NO WHERE FR.EMP_ID = #{empId}

SELECT TO_CHAR(RM_RSVT_BGNG_DT, 'HH24:MI') || '-' ||
TO_CHAR(RM_RSVT_END_DT, 'HH24:MI')
FROM ROOM_RESERVATION
WHERE RM_NO = #{rmNo}
AND (APRV_STTS IS NULL OR APRV_STTS != 'REJECTED')
AND TO_CHAR(RM_RSVT_BGNG_DT, 'YYYY-MM-DD') = #{date}

choose.when:
UPDATE ROOM_RESERVATION
SET RM_RSVT_APRV_DT = SYSDATE

    , APRV_STTS = #{status}

WHERE RM_RSVT_NO = #{resId}

choose.otherwise:
UPDATE FIXTURE_RESERVATION
SET FIXT_RSVT_APRV_DT = SYSDATE

    , APRV_STTS = #{status}

WHERE FIXT_RSVT_NO = #{resId}

mapper.delete:
BEGIN
DELETE FROM ROOM_RESERVATION WHERE RM_NO = #{rmNo};
DELETE FROM MEETING_ROOM WHERE RM_NO = #{rmNo};
END;

mapper.insert:

       	SELECT NVL(MAX(FIXT_NO), 0) + 1 FROM FIXTURE

	BEGIN
	INSERT INTO FIXTURE (FIXT_NO, FIXT_CAT, FIXT_NM, FIXT_QTY, FIXT_STTS, ASSET_NO) 
	VALUES (#{fixtNo}, #{fixtCat}, #{fixtNm}, #{fixtQty}, #{fixtStts}, #{assetNo}); 


	INSERT INTO FIXTURE_MODEL (FIXT_NO, FIXT_MD_NM)
	VALUES (#{fixtNo}, #{fixtMdNm, jdbcType=VARCHAR});

	END;

mapper.delete:
BEGIN
DELETE FROM FIXTURE_RESERVATION WHERE FIXT_NO = #{fixtNo};
DELETE FROM FIXTURE_MODEL WHERE FIXT_NO = #{fixtNo};
DELETE FROM FIXTURE WHERE FIXT_NO = #{fixtNo};
END;
